import React, { useState, useEffect, useRef } from 'react';
import { useAuth } from '../context/AuthContext';
import axios from 'axios';

const CARD_STYLES = [
  {
    id: 'wallet',
    label: 'Wallet Card',
    icon: '💳',
    desc: 'Credit card size — fits in wallet or ID holder',
    size: '85mm × 54mm',
    bg: '#0a0f1e',
    accent: '#ef4444',
    textColor: '#f1f5f9',
    border: '2px solid #ef4444',
  },
  {
    id: 'helmet',
    label: 'Helmet Sticker',
    icon: '🪖',
    desc: 'Compact square — stick on helmet or bike',
    size: '60mm × 60mm',
    bg: '#111827',
    accent: '#f59e0b',
    textColor: '#f1f5f9',
    border: '2px solid #f59e0b',
  },
  {
    id: 'car',
    label: 'Car / Dashboard',
    icon: '🚗',
    desc: 'Wide card — place on dashboard or visor',
    size: '120mm × 60mm',
    bg: '#1a1a2e',
    accent: '#3b82f6',
    textColor: '#f1f5f9',
    border: '2px solid #3b82f6',
  },
  {
    id: 'badge',
    label: 'ID Badge',
    icon: '🪪',
    desc: 'Portrait format — hang around neck',
    size: '54mm × 85mm',
    bg: '#0f172a',
    accent: '#10b981',
    textColor: '#f1f5f9',
    border: '2px solid #10b981',
  },
];

function Toast({ msg, type, onClose }) {
  useEffect(() => { const t = setTimeout(onClose, 3000); return () => clearTimeout(t); }, [onClose]);
  return <div className={`toast toast-${type}`}>{msg}</div>;
}

export default function QRPage() {
  const { API } = useAuth();
  const [qr, setQr] = useState(null);
  const [profile, setProfile] = useState(null);
  const [loading, setLoading] = useState(true);
  const [generating, setGenerating] = useState(false);
  const [selectedStyle, setSelectedStyle] = useState('wallet');
  const [toast, setToast] = useState(null);
  const printRef = useRef();

  const showToast = (msg, type = 'success') => setToast({ msg, type });

  useEffect(() => {
    Promise.all([
      axios.get(`${API}/qr/active`),
      axios.get(`${API}/profile`)
    ]).then(([qRes, pRes]) => {
      setQr(qRes.data.qr);
      setProfile(pRes.data.profile);
    }).finally(() => setLoading(false));
  }, [API]);

  const generateQR = async () => {
    setGenerating(true);
    try {
      const res = await axios.post(`${API}/qr/generate`);
      setQr({ ...res.data, qrDataUrl: res.data.qrDataUrl });
      showToast('New QR code generated!');
    } catch {
      showToast('Failed to generate QR code.', 'error');
    } finally {
      setGenerating(false);
    }
  };

  const handlePrint = () => {
    const style = CARD_STYLES.find(s => s.id === selectedStyle);
    const printWindow = window.open('', '_blank');
    printWindow.document.write(`
      <!DOCTYPE html>
      <html>
      <head>
        <title>LifeQR — ${style.label}</title>
        <link href="https://fonts.googleapis.com/css2?family=Space+Grotesk:wght@400;600;700&family=DM+Sans:wght@400;500&display=swap" rel="stylesheet">
        <style>
          * { margin: 0; padding: 0; box-sizing: border-box; }
          body { background: #f0f0f0; display: flex; align-items: center; justify-content: center; min-height: 100vh; font-family: 'DM Sans', sans-serif; }
          .page { display: flex; flex-direction: column; align-items: center; gap: 32px; padding: 40px; }
          .instructions { font-size: 13px; color: #666; text-align: center; max-width: 500px; line-height: 1.6; }
          @media print {
            body { background: white; }
            .instructions { display: none; }
            .card { break-inside: avoid; }
          }
        </style>
      </head>
      <body>
        <div class="page">
          <div class="instructions">
            <strong>LifeQR Printable Card</strong><br/>
            Print this page and cut along the border. Place it on your ${style.id}.<br/>
            Use good quality paper or laminate for durability.
          </div>
          ${printRef.current.innerHTML}
        </div>
        <script>setTimeout(() => window.print(), 500);<\/script>
      </body>
      </html>
    `);
    printWindow.document.close();
  };

  const style = CARD_STYLES.find(s => s.id === selectedStyle);

  if (loading) return (
    <div style={{ display: 'flex', justifyContent: 'center', alignItems: 'center', height: '60vh' }}>
      <div className="spinner" style={{ width: 40, height: 40 }} />
    </div>
  );

  return (
    <div className="page-container">
      {toast && <Toast msg={toast.msg} type={toast.type} onClose={() => setToast(null)} />}

      <div style={{ marginBottom: 32 }}>
        <h1 style={{ fontFamily: 'Space Grotesk', fontSize: 28, fontWeight: 700, marginBottom: 6 }}>My LifeQR Code</h1>
        <p style={{ color: 'var(--text2)' }}>Generate, customize and print your emergency QR card.</p>
      </div>

      {!qr ? (
        /* No QR yet */
        <div className="card" style={{ textAlign: 'center', padding: 60 }}>
          <div style={{ fontSize: 64, marginBottom: 20 }}>🔲</div>
          <h2 style={{ fontFamily: 'Space Grotesk', fontSize: 24, marginBottom: 12 }}>Generate Your QR Code</h2>
          <p style={{ color: 'var(--text2)', maxWidth: 400, margin: '0 auto 32px', lineHeight: 1.7 }}>
            Your unique QR code will link to your emergency medical profile. Anyone scanning it can reach your family instantly.
          </p>
          <button className="btn btn-primary btn-lg" onClick={generateQR} disabled={generating}>
            {generating ? <><div className="spinner" />Generating...</> : '🔲 Generate My QR Code'}
          </button>
        </div>
      ) : (
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 24, alignItems: 'start' }}>
          {/* Left: Controls */}
          <div style={{ display: 'flex', flexDirection: 'column', gap: 20 }}>

            {/* QR Info */}
            <div className="card">
              <div className="section-title"><div className="icon">🔲</div>Active QR Code</div>
              <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
                <img src={qr.qrDataUrl} alt="QR" style={{ width: 100, height: 100, borderRadius: 8 }} />
                <div>
                  <div style={{ fontSize: 13, color: 'var(--text2)', marginBottom: 6 }}>
                    <span className="badge badge-green">● Active</span>
                  </div>
                  <div style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 4 }}>
                    Expires: {new Date(qr.expires_at).toLocaleDateString('en-IN', { day: 'numeric', month: 'long', year: 'numeric' })}
                  </div>
                  <div style={{ fontSize: 11, color: 'var(--text3)', wordBreak: 'break-all', maxWidth: 180 }}>
                    {qr.scanUrl}
                  </div>
                </div>
              </div>
              <div className="divider" />
              <button className="btn btn-ghost btn-full" style={{ fontSize: 13 }} onClick={generateQR} disabled={generating}>
                {generating ? <><div className="spinner" />Regenerating...</> : '🔄 Regenerate QR (creates new token)'}
              </button>
            </div>

            {/* Card Style Picker */}
            <div className="card">
              <div className="section-title"><div className="icon">🎨</div>Choose Card Style</div>
              <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                {CARD_STYLES.map(s => (
                  <button key={s.id} onClick={() => setSelectedStyle(s.id)}
                    style={{
                      display: 'flex', alignItems: 'center', gap: 14,
                      background: selectedStyle === s.id ? 'rgba(239,68,68,0.1)' : 'var(--bg3)',
                      border: selectedStyle === s.id ? '1px solid rgba(239,68,68,0.4)' : '1px solid var(--border)',
                      borderRadius: 10, padding: '12px 14px', cursor: 'pointer', width: '100%', textAlign: 'left',
                      transition: 'all 0.15s'
                    }}>
                    <span style={{ fontSize: 24 }}>{s.icon}</span>
                    <div style={{ flex: 1 }}>
                      <div style={{ fontFamily: 'Space Grotesk', fontWeight: 600, fontSize: 14, color: 'var(--text)' }}>{s.label}</div>
                      <div style={{ fontSize: 12, color: 'var(--text3)' }}>{s.desc} · {s.size}</div>
                    </div>
                    {selectedStyle === s.id && <span style={{ color: 'var(--red)' }}>✓</span>}
                  </button>
                ))}
              </div>
            </div>

            {/* Print Button */}
            <button className="btn btn-primary btn-lg" onClick={handlePrint}>
              🖨️ Print {style.label}
            </button>
            <p style={{ fontSize: 12, color: 'var(--text3)', textAlign: 'center', marginTop: -8 }}>
              Opens a print-ready page. Laminate for durability.
            </p>
          </div>

          {/* Right: Live Preview */}
          <div>
            <div style={{ fontFamily: 'Space Grotesk', fontWeight: 600, marginBottom: 14, color: 'var(--text2)', fontSize: 13, textTransform: 'uppercase', letterSpacing: '0.08em' }}>
              Preview — {style.label}
            </div>

            {/* Card Preview Container */}
            <div ref={printRef}>
              <PrintableCard style={style} qr={qr} profile={profile} />
            </div>

            <div style={{ marginTop: 16, padding: '12px 16px', background: 'var(--bg3)', borderRadius: 10, fontSize: 13, color: 'var(--text2)', lineHeight: 1.7 }}>
              <strong style={{ color: 'var(--text)' }}>💡 Tips for best results:</strong><br />
              • Print on thick cardstock (200gsm or more)<br />
              • Laminate wallet cards for water resistance<br />
              • Use weatherproof sticker paper for helmets/bikes<br />
              • Test scan before placing permanently
            </div>
          </div>
        </div>
      )}
    </div>
  );
}

function PrintableCard({ style, qr, profile }) {
  const isWide = style.id === 'car';
  const isTall = style.id === 'badge';
  const isSquare = style.id === 'helmet';

  const cardStyle = {
    background: style.bg,
    border: style.border,
    borderRadius: 16,
    padding: isSquare ? 16 : 20,
    color: style.textColor,
    fontFamily: "'DM Sans', sans-serif",
    display: 'flex',
    flexDirection: isTall ? 'column' : isWide ? 'row' : 'row',
    alignItems: 'center',
    gap: isSquare ? 12 : 16,
    width: '100%',
    maxWidth: isWide ? 520 : isTall ? 260 : 380,
    minHeight: isTall ? 420 : isSquare ? 220 : 180,
    boxShadow: `0 0 0 4px ${style.accent}22, 0 8px 32px rgba(0,0,0,0.5)`,
    position: 'relative',
    overflow: 'hidden',
  };

  return (
    <div style={cardStyle}>
      {/* Decorative circle bg */}
      <div style={{
        position: 'absolute', top: -40, right: -40,
        width: 160, height: 160, borderRadius: '50%',
        background: `${style.accent}15`, pointerEvents: 'none'
      }} />

      {/* QR Code */}
      <div style={{
        background: 'white', padding: 8, borderRadius: 12, flexShrink: 0,
        border: `3px solid ${style.accent}`
      }}>
        <img src={qr.qrDataUrl} alt="LifeQR"
          style={{ width: isSquare ? 80 : isTall ? 130 : 110, height: isSquare ? 80 : isTall ? 130 : 110, display: 'block' }} />
      </div>

      {/* Info */}
      <div style={{ flex: 1, zIndex: 1 }}>
        {/* Logo */}
        <div style={{
          display: 'flex', alignItems: 'center', gap: 6, marginBottom: isSquare ? 6 : 10
        }}>
          <span style={{ fontSize: isSquare ? 14 : 18 }}>❤️‍🔥</span>
          <span style={{
            fontFamily: 'Space Grotesk, sans-serif', fontWeight: 700,
            fontSize: isSquare ? 14 : 17, color: style.accent
          }}>
            Life<span style={{ color: style.textColor }}>QR</span>
          </span>
        </div>

        {/* Name */}
        <div style={{
          fontFamily: 'Space Grotesk, sans-serif', fontWeight: 700,
          fontSize: isSquare ? 15 : isTall ? 20 : 18, marginBottom: 4, color: style.textColor
        }}>
          {profile?.full_name || 'Your Name'}
        </div>

        {/* Blood type badge */}
        {profile?.blood_type && (
          <div style={{
            display: 'inline-block',
            background: style.accent, color: '#fff',
            borderRadius: 6, padding: '2px 10px',
            fontSize: 13, fontWeight: 700, marginBottom: 8
          }}>
            Blood: {profile.blood_type}
          </div>
        )}

        {!isSquare && (
          <>
            {profile?.allergies && (
              <div style={{ fontSize: 12, color: `${style.textColor}bb`, marginBottom: 3 }}>
                ⚠️ Allergies: {profile.allergies.substring(0, 40)}{profile.allergies.length > 40 ? '...' : ''}
              </div>
            )}
            <div style={{
              fontSize: isSquare ? 10 : 11, color: style.accent,
              marginTop: 6, fontWeight: 600, letterSpacing: '0.04em'
            }}>
              📱 SCAN FOR EMERGENCY INFO
            </div>
          </>
        )}

        {isSquare && (
          <div style={{ fontSize: 10, color: style.accent, fontWeight: 700, letterSpacing: '0.04em' }}>
            📱 SCAN IN EMERGENCY
          </div>
        )}
      </div>

      {/* Corner accent */}
      <div style={{
        position: 'absolute', bottom: 0, left: 0, right: 0,
        height: 3, background: `linear-gradient(90deg, ${style.accent}, transparent)`
      }} />
    </div>
  );
}
